# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

import collections

def process_transactions(transactions, initial_balances):
    balances = collections.defaultdict(float)
    for account, balance in initial_balances.items():
        balances[account] = balance

    for transaction in transactions:
        transaction_type = transaction['type']
        amount = transaction['amount']
        account = transaction['account']

        if transaction_type == 'deposit':
            balances[account] += amount
        elif transaction_type == 'withdrawal':
            if balances[account] >= amount:
                balances[account] -= amount
            else:
                # Optionally, handle insufficient funds error or log it
                print(f"Insufficient funds for withdrawal of {amount} from {account}. Current balance: {balances[account]}")
        elif transaction_type == 'transfer':
            from_account = transaction['from_account']
            to_account = transaction['to_account']
            if balances[from_account] >= amount:
                balances[from_account] -= amount
                balances[to_account] += amount
            else:
                # Optionally, handle insufficient funds for transfer
                print(f"Insufficient funds for transfer of {amount} from {from_account}. Current balance: {balances[from_account]}")
        else:
            # Optionally, handle unknown transaction types
            print(f"Unknown transaction type: {transaction_type}")
            
    return dict(balances)